-- [ ObfusPro+ ]
local SbDuU = bit32 or bit or error("ObfusPro+: Environment error");
local function PcurtE(xiJcg)
    local hZXIhGVx = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local YlauA = string.gsub(xiJcg, '[^' .. hZXIhGVx .. ']', '')
    local utGrBNu = {}
    for uvBa = 1, #YlauA, 4 do
        local Fvv, JUk, QxC, FEU = string.byte(YlauA, uvBa, uvBa + 3)
        if not Fvv then break end
        local udOz = string.find(hZXIhGVx, string.char(Fvv)) - 1
        local mJap = string.find(hZXIhGVx, string.char(JUk)) - 1
        local yZGN = QxC and string.find(hZXIhGVx, string.char(QxC)) - 1 or 0
        local IKRQ = FEU and string.find(hZXIhGVx, string.char(FEU)) - 1 or 0
        local DXfi = udOz * 262144 + mJap * 4096 + yZGN * 64 + IKRQ
        local djeS = SbDuU.band(SbDuU.rshift(DXfi, 16), 255)
        table.insert(utGrBNu, string.char(SbDuU.bxor(djeS, 42)))
        if QxC and string.char(QxC) ~= '=' then
            djeS = SbDuU.band(SbDuU.rshift(DXfi, 8), 255)
            table.insert(utGrBNu, string.char(SbDuU.bxor(djeS, 42)))
        end
        if FEU and string.char(FEU) ~= '=' then
            djeS = SbDuU.band(DXfi, 255)
            table.insert(utGrBNu, string.char(SbDuU.bxor(djeS, 42)))
        end
    end
    return table.concat(utGrBNu)
end
